            throw new IOException("ZIP file does not exist: " + zipPath);
        }
        if (!Files.isRegularFile(zipPath)) {
            throw new IOException("Specified ZIP path is not a file: " + zipPath);
        }
        if (!Files.isReadable(zipPath)) {
            throw new IOException("ZIP file is not readable: " + zipPath);
        }

        // Create target directory if it does not exist.
        Files.createDirectories(targetDir);

        List<String> extractedFiles = new ArrayList<>();

        try (InputStream fileInputStream = Files.newInputStream(zipPath);
             ZipInputStream zipInputStream = new ZipInputStream(fileInputStream)) {

            ZipEntry entry;
            while ((entry = zipInputStream.getNextEntry()) != null) {
                String entryName = entry.getName();

                // Skip invalid empty entry names.
                if (entryName == null || entryName.trim().isEmpty()) {
                    zipInputStream.closeEntry();
                    continue;
                }

                Path resolvedPath = targetDir.resolve(entryName).normalize();

                // Prevent Zip Slip vulnerability.
                if (!resolvedPath.startsWith(targetDir)) {
                    zipInputStream.closeEntry();
                    throw new IOException("Blocked unsafe ZIP entry: " + entryName);
                }

                if (entry.isDirectory()) {
                    Files.createDirectories(resolvedPath);
                } else {
                    Path parent = resolvedPath.getParent();
                    if (parent != null) {
                        Files.createDirectories(parent);
                    }

                    try (OutputStream outputStream = Files.newOutputStream(
                            resolvedPath,
                            StandardOpenOption.CREATE,
                            StandardOpenOption.TRUNCATE_EXISTING,
                            StandardOpenOption.WRITE)) {

                        byte[] buffer = new byte[8192];
                        int bytesRead;
                        while ((bytesRead = zipInputStream.read(buffer)) != -1) {
                            outputStream.write(buffer, 0, bytesRead);
                        }
                    }

                    extractedFiles.add(resolvedPath.toAbsolutePath().toString());
                }

                zipInputStream.closeEntry();
            }
        }

        return extractedFiles;
    }
}
